+    local procedure NavigateToSalesCreditMemo(DocumentNo: Code[20]): Boolean
+    var
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+        PostedSalesCreditMemo: Page "Posted Sales Credit Memo";
+    begin
+        // An IC Transaction of type Sales Credit Memo can only be sent when posted, not received.
+        if not SalesCrMemoHeader.Get(DocumentNo) then
+            exit(false);
+        // The related document is a Posted Sales Credit Memo.
+        PostedSalesCreditMemo.SetRecord(SalesCrMemoHeader);
+        PostedSalesCreditMemo.Run();
+        exit(true);
+    end;
+
+    local procedure NavigateToSalesCreditMemo(DocumentNo: Code[20]; ICPartnerCode: Code[20]): Boolean
+    var
+        Customer: Record Customer;
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+        PostedSalesCreditMemo: Page "Posted Sales Credit Memo";
+    begin
+        // This is called when we couldn't find a related sales return order,
+        // so we attempt to find a Posted Sales Credit Memo
+        Customer.SetRange("IC Partner Code", ICPartnerCode);
+        if not Customer.FindSet() then
+            exit(false);
+        repeat
+            SalesCrMemoHeader.Reset();
+            SalesCrMemoHeader.SetRange("Return Order No.", DocumentNo);
+            SalesCrMemoHeader.SetRange("Sell-to Customer No.", Customer."No.");
