+    local procedure CorrectQuantityRoundingInTracking(LastEntryNo: Integer; OriginalQtyToTrack: Decimal)
+    var
+        TrackingEntry: Record "Reservation Entry";
+        TotalAllocatedBase: Decimal;
+        TotalAllocatedRounded: Decimal;
+        RoundingError: Decimal;
+    begin
+        // This procedure corrects rounding errors that occur when splitting quantities
+        // across multiple tracking entries. It ensures that the total allocated quantity
+        // equals exactly the original quantity that was to be tracked.
+        
+        if LastEntryNo = 0 then
+            exit;
+        
+        if not TrackingEntry.Get(LastEntryNo, TrackingEntry.Positive) then
+            exit;
+        
+        // Get all tracking entries for the same source and calculate their total
+        TrackingEntry.SetCurrentKey(
+            "Item No.", "Variant Code", "Location Code", "Reservation Status",
+            "Shipment Date", "Expected Receipt Date", "Serial No.", "Lot No.");
+        TrackingEntry.SetRange("Item No.", TrackingEntry."Item No.");
+        TrackingEntry.SetRange("Variant Code", TrackingEntry."Variant Code");
+        TrackingEntry.SetRange("Location Code", TrackingEntry."Location Code");
+        TrackingEntry.SetRange("Reservation Status", TrackingEntry."Reservation Status");
+        TrackingEntry.SetRange(Positive, TrackingEntry.Positive);
+        TrackingEntry.SetRange("Source Type", TrackingEntry."Source Type");
+        TrackingEntry.SetRange("Source Subtype", TrackingEntry."Source Subtype");
+        TrackingEntry.SetRange("Source ID", TrackingEntry."Source ID");
+        TrackingEntry.SetRange("Source Ref. No.", TrackingEntry."Source Ref. No.");
+        TrackingEntry.SetTrackingFilterFromReservEntry(TrackingEntry);
+        
+        if TrackingEntry.FindSet() then
+            repeat
+                TotalAllocatedBase += TrackingEntry."Quantity (Base)";
+            until TrackingEntry.Next() = 0;
+        
+        // Check if there's a rounding error
+        if Abs(TotalAllocatedBase) > 0 then begin
+            // Calculate what the total should be when rounded
+            TotalAllocatedRounded := Round(TotalAllocatedBase / TrackingEntry."Qty. per Unit of Measure", UOMMgt.QtyRndPrecision()) * TrackingEntry."Qty. per Unit of Measure";
+            RoundingError := TotalAllocatedBase - TotalAllocatedRounded;
+            
+            if RoundingError <> 0 then begin
+                // Adjust the last entry by the rounding error
+                TrackingEntry.Get(LastEntryNo, TrackingEntry.Positive);
+                TrackingEntry."Quantity (Base)" -= RoundingError;
+                TrackingEntry.Modify(false);
+            end;
+        end;
